#include <bits/stdc++.h>
using namespace std;
long long extgcd(long long a,long long b,long long &x,long long &y){
    if(b==0){
        x=1,y=0;
        return a;
    }
    long long gcd=extgcd(b,a%b,x,y),t=x-a/b*y;
    x=y,y=t;
    return gcd;
}
int main(){
    long long a,b,x,y,gcd,lcm;
    cin>>a>>b;
    gcd=extgcd(a,b,x,y),lcm=a*b/gcd;
    while(x<=0)
    	x+=lcm/a;
    cout<<x/gcd;
    return 0;
}
